8649 static void addCanonicalIVRecipes(VPlan &Plan, Type *IdxTy, bool HasNUW,
8650                                   DebugLoc DL) {
8651   Value *StartIdx = ConstantInt::get(IdxTy, 0);
8652   auto *StartV = Plan.getOrAddLiveIn(StartIdx);
