1369   SmallVector<Value *, 4> Ops;
1370   for (unsigned I = 0, E = getNumOperands() - 1; I < E; ++I) {
1371     VPValue *VPOp = getOperand(I);
1372     Ops.push_back(State.get(VPOp));
1373   }
