458     //
459     //   vector.ph:
460     //     v_init = vector(..., ..., ..., a[-1])
461     //     br vector.body
462     //
463     //   vector.body
464     //     i = phi [0, vector.ph], [i+4, vector.body]
465     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
466     //     v2 = a[i, i+1, i+2, i+3];
467     //     v3 = vector(v1(3), v2(0, 1, 2))
468 
469     auto *V1 = State.get(getOperand(0));
